import React from 'react';
import './Brands.css';

const Brands = () => {
  const brands = ['Proton', 'Perodua', 'Toyota', 'Honda', 'Nissan', 'BMW', 'Mercedes', 'Mazda', 'Any Car'];

  return (
    <section id="brands" className="brands">
      <h2>Car Brands We Have <span>Experience With</span></h2>
      <div className="brands-grid">
        {brands.map((brand, i) => (
          <div key={i} className={`brand-card ${brand === 'Any Car' ? 'brand-wide' : ''}`}>
            <span className="brand-icon">🚗</span>
            <p>{brand}</p>
          </div>
        ))}
      </div>
    </section>
  );
};

export default Brands;
